package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Arrays;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testToString_Default() {
        String str = csvFormat.toString();
        assertTrue(str.contains("Delimiter=<,>"));
        assertTrue(str.contains("QuoteChar=<\""));
        assertTrue(str.contains("SkipHeaderRecord:false"));
        assertTrue(str.contains("EmptyLines:ignored"));
        assertTrue(str.contains("SurroundingSpaces:ignored"));
        assertTrue(str.contains("IgnoreHeaderCase:ignored"));
    }

    @Test
    void testToString_WithEscapeCharacter() throws Exception {
        CSVFormat format = createCSVFormatWithField("escapeCharacter", '\\');
        String str = format.toString();
        assertTrue(str.contains("Escape=<\\>"));
    }

    @Test
    void testToString_WithCommentMarker() throws Exception {
        CSVFormat format = createCSVFormatWithField("commentMarker", '#');
        String str = format.toString();
        assertTrue(str.contains("CommentStart=<#>"));
    }

    @Test
    void testToString_WithNullString() throws Exception {
        CSVFormat format = createCSVFormatWithField("nullString", "NULL");
        String str = format.toString();
        assertTrue(str.contains("NullString=<NULL>"));
    }

    @Test
    void testToString_WithRecordSeparator() throws Exception {
        CSVFormat format = createCSVFormatWithField("recordSeparator", "\n");
        String str = format.toString();
        assertTrue(str.contains("RecordSeparator=<\n>") || str.contains("RecordSeparator=<\r\n>"));
    }

    @Test
    void testToString_IgnoreFlags() throws Exception {
        CSVFormat format = csvFormat
                .withIgnoreEmptyLines(false)
                .withIgnoreSurroundingSpaces(false)
                .withIgnoreHeaderCase(false);
        String str = format.toString();
        assertFalse(str.contains("EmptyLines:ignored"));
        assertFalse(str.contains("SurroundingSpaces:ignored"));
        assertFalse(str.contains("IgnoreHeaderCase:ignored"));

        format = csvFormat
                .withIgnoreEmptyLines(true)
                .withIgnoreSurroundingSpaces(true)
                .withIgnoreHeaderCase(true);
        str = format.toString();
        assertTrue(str.contains("EmptyLines:ignored"));
        assertTrue(str.contains("SurroundingSpaces:ignored"));
        assertTrue(str.contains("IgnoreHeaderCase:ignored"));
    }

    @Test
    void testToString_WithHeaderCommentsAndHeader() throws Exception {
        CSVFormat format = csvFormat
                .withHeaderComments("comment1", "comment2")
                .withHeader("header1", "header2");
        String str = format.toString();
        assertTrue(str.contains("HeaderComments:[comment1, comment2]"));
        assertTrue(str.contains("Header:[header1, header2]"));
    }

    @Test
    void testToString_SkipHeaderRecordTrue() throws Exception {
        CSVFormat format = csvFormat.withSkipHeaderRecord(true);
        String str = format.toString();
        assertTrue(str.contains("SkipHeaderRecord:true"));
    }

    // Helper method to create a new CSVFormat with a private field set via reflection
    private CSVFormat createCSVFormatWithField(String fieldName, Object value) throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Create a new CSVFormat instance copying DEFAULT and overriding the field
        CSVFormat newFormat = CSVFormat.DEFAULT;
        // Because CSVFormat is immutable, we use 'with' methods if available for public fields
        switch (fieldName) {
            case "escapeCharacter":
                newFormat = format.withEscape((Character) value);
                break;
            case "commentMarker":
                newFormat = format.withCommentMarker((Character) value);
                break;
            case "nullString":
                newFormat = format.withNullString((String) value);
                break;
            case "recordSeparator":
                newFormat = format.withRecordSeparator((String) value);
                break;
            default:
                // For other fields, try to set via reflection on a new instance
                // But CSVFormat is final and immutable, so we rely on with* methods
                break;
        }
        return newFormat;
    }
}
